module RefModule(A, B, SUB, SUM);input [3:0] A, B;
  input SUB;
  output reg [3:0] SUM;  // Change output to reg type

  reg [3:0] final_sig;

  always @(*) begin
    if(SUB == 0) begin
      final_sig = A + B;
      SUM = final_sig;
    end
    else begin
      final_sig = A - B;
      SUM = final_sig;
    end
  end
endmodule
